'use client';

import { motion, useInView, useMotionValue, useSpring } from 'framer-motion';
import { useEffect, useRef, useState } from 'react';

interface CountUpOnViewProps {
  label: string;
  value: number;
  suffix?: string;
}

export default function CountUpOnView({ label, value, suffix = '' }: CountUpOnViewProps) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });
  const motionValue = useMotionValue(0);
  const spring = useSpring(motionValue, { stiffness: 90, damping: 18 });
  const [displayValue, setDisplayValue] = useState(0);

  useEffect(() => {
    if (!isInView) return;
    motionValue.set(value);
  }, [isInView, motionValue, value]);

  useEffect(() => {
    return spring.on('change', (latest) => setDisplayValue(Math.round(latest)));
  }, [spring]);

  return (
    <div ref={ref} className="overflow-hidden rounded-[2rem] border border-white/10 bg-white/5 p-8 backdrop-blur-xl">
      <p className="text-5xl font-semibold tracking-tight text-white">{displayValue}{suffix}</p>
      <p className="mt-4 uppercase tracking-[0.35em] text-sm text-amber-200/80">{label}</p>
    </div>
  );
}
