'use client';

import { motion, useScroll, useTransform } from 'framer-motion';
import { Fragment, useMemo, useRef } from 'react';

interface TextRevealProps {
  text: string;
}

export default function TextReveal({ text }: TextRevealProps) {
  const ref = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ['start end', 'end start'] });
  const opacity = useTransform(scrollYProgress, [0, 0.15, 0.35, 1], [0, 1, 1, 0]);
  const y = useTransform(scrollYProgress, [0, 0.35], [40, 0]);
  const letters = useMemo(() => text.split(''), [text]);

  return (
    <motion.div ref={ref} style={{ opacity, y }} className="overflow-hidden text-lg leading-relaxed text-stone-100/90 md:text-xl">
      <p className="inline-flex flex-wrap gap-[0.1em]">
        {letters.map((char, index) => (
          <motion.span
            key={`${char}-${index}`}
            initial={{ opacity: 0, y: 24 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.01, duration: 0.45, ease: 'easeOut' }}
            className="inline-block"
          >
            {char}
          </motion.span>
        ))}
      </p>
    </motion.div>
  );
}
